import React from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";
import { useAuth } from "../contexts/AuthContext";

const NAV_LINKS = [
  { label: "projects", to: "/projects" },
  { label: "contact", to: "/contact" },
  { label: "members login", to: "/login" },
  { label: "admin login", to: "/admin/login" },
];

export const Logo = () => (
  <svg viewBox="0 0 256 256" className="h-5 w-5" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
    <path d="M 128 192 L 128 256 L 64.5 256 L 32 223 L 0 192 L 0 128 L 64 128 Z M 256 192 L 256 256 L 192.5 256 L 160 223 L 128 192 L 128 128 L 192 128 Z M 128 64 L 128 128 L 64.5 128 L 32 95 L 0 64 L 0 0 L 64 0 Z M 256 64 L 256 128 L 192.5 128 L 160 95 L 128 64 L 128 0 L 192 0 Z" fill="#ffffff" />
  </svg>
);

export default function Navbar({ floating = true }) {
  const { user, logout } = useAuth();
  const loc = useLocation();
  const nav = useNavigate();

  return (
    <div className={floating ? "absolute z-20 px-6 md:px-10 pt-6 top-0 left-0 right-0" : "px-6 md:px-10 pt-6"}>
      <nav className="flex items-center justify-between gap-4">
        <Link to="/" data-testid="nav-brand" className="flex items-center gap-2 bg-neutral-900/90 backdrop-blur rounded-full pl-4 pr-6 py-3">
          <Logo />
          <span className="text-white text-sm font-normal tracking-tight">spectral forge</span>
        </Link>

        <div className="hidden md:flex items-center gap-1 bg-neutral-900/90 backdrop-blur rounded-full px-3 py-2">
          {NAV_LINKS.map((l) => (
            <Link
              key={l.to}
              to={l.to}
              data-testid={`nav-link-${l.label}`}
              className={`text-sm px-5 py-2 rounded-full transition-colors ${
                loc.pathname === l.to ? "text-white" : "text-neutral-300 hover:text-white"
              }`}
            >
              {l.label}
            </Link>
          ))}
        </div>

        <div className="flex items-center gap-2">
          {user ? (
            <>
              <Link
                to={user.role === "admin" ? "/admin" : "/dashboard"}
                data-testid="nav-dashboard-btn"
                className="hidden sm:inline-block bg-neutral-900/90 backdrop-blur text-white text-sm rounded-full px-5 py-3 hover:bg-neutral-800 transition-colors"
              >
                {user.role === "admin" ? "admin" : "dashboard"}
              </Link>
              <button
                onClick={() => { logout(); nav("/"); }}
                data-testid="nav-logout-btn"
                className="bg-white text-black text-sm font-normal rounded-full px-6 py-3 hover:bg-neutral-200 transition-colors"
              >
                logout
              </button>
            </>
          ) : (
            <Link
              to="/login"
              data-testid="nav-get-started-btn"
              className="bg-white text-black text-sm font-normal rounded-full px-6 py-3 hover:bg-neutral-200 transition-colors"
            >
              members login
            </Link>
          )}
        </div>
      </nav>
    </div>
  );
}
